### Load data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)
options(chromote.headless = "new")

# scrape data manually 
# https://www.ncaa.com/news/basketball-men/article/2024-10-14/kansas-alabama-uconn-lead-mens-basketball-ap-preseason-poll

# rankings_pivoted <- rankings |> 
#  dplyr::mutate(
#    `Sweet 16` = ifelse(Season_Finish == "Sweet 16", 1, 0),
#    `Round of 32` = ifelse(Season_Finish %in% c("Sweet 16", "Round of 32"), 1, 0),
#    `Round of 64` = ifelse(Season_Finish %in% c("Sweet 16", "Round of 32", "Round of 64"), 1, 0),
#    `First Four` = ifelse(Season_Finish == "First Four", 1, 0),
#    `Missed Tournament` = ifelse(Season_Finish == "Missed Tournament", 1, 0)
#  ) |> 
#  dplyr::select(Rank, Team, `Sweet 16`, `Round of 32`, `Round of 64`, `First Four`, `Missed Tournament`)

# load via csv for easier handling in quarto 
rpivot <- readr::read_csv("rpivot.csv")

# NCAAT shooting data with assist from cobrastats 
ncaatg <- readr::read_csv("ncaat-shooting.csv")

ncaalog <- ncaatg |> 
  dplyr::mutate(round = dplyr::case_match(round,
                                          "0. FIRST FOUR" ~ "First4",
                                          "1. ROUND OF 64" ~ "R64",
                                          "2. ROUND OF 32" ~ "R32",
                                          "3. SWEET SIXTEEN" ~ "S16",
                                          "4. ELITE EIGHT" ~ "E8",
                                          "5. FINAL FOUR" ~ "Final4",
                                          "6. CHAMPIONSHIP" ~ "F2"
  )) |> 
  dplyr::group_by(year, round) |> 
  dplyr::summarise(
    made_3 = sum(tpm),
    attempt_3 = sum(tpa),
    pct_3 = made_3 / attempt_3
  ) |> 
  dplyr::arrange(year)

ncaalog_wide <- ncaalog |> 
  dplyr::filter(year > 2010) |> 
  dplyr::mutate(made_attempt = paste0(made_3, "-", attempt_3)) |> 
  dplyr::select(year, round, made_attempt, pct_3) |> 
  tidyr::pivot_wider(
    names_from = round, 
    values_from = c(made_attempt, pct_3),
    names_glue = "{round}_{.value}"
  ) |> 
  dplyr::select(
    year, 
    First4_made_attempt, First4_pct_3,
    R64_made_attempt, R64_pct_3,
    R32_made_attempt, R32_pct_3,
    S16_made_attempt, S16_pct_3,
    E8_made_attempt, E8_pct_3,
    Final4_made_attempt, Final4_pct_3,
    F2_made_attempt, F2_pct_3
  ) |> 
  dplyr::ungroup()
```
:::


