ap_poll_tbl <- rpivot |>
  cbbplotR::gt_cbb_teams(Team, Team, logo_height = 20) |>
  gt::gt() |>
  gt::fmt_markdown(columns = Team) |>
  gtUtils::gt_theme_gtutils() |>
  gtUtils::gt_indicator_boxes(
    key_columns = c("Rank", "Team"),
    color_yes = "lightgreen",
    color_no = "lightpink",
    color_na = "#e1e1e1",
    border_color = "black",
    border_width = 0.5,
    box_width = 16,
    box_height = 16
  ) |>
  gt::cols_align(Team, align = "left") |>
  gt::cols_align(Rank, align = "right") |>
  gtUtils::gt_column_subheaders(
    Rank = list(heading = "Rank", subtitle = "AP Top-25"),
    `Missed Tournament` = list(heading = "Missed", subtitle = "NCAA Tournament"),
    `First Four` = list(heading = "First Four", subtitle = "Round of 68"),
    `Round of 64` = list(heading = "1st Round", subtitle = "Round of 64"),
    `Round of 32` = list(heading = "2nd Round", subtitle = "Round of 32"),
    `Sweet 16` = list(heading = "Sweet 16", subtitle = "2nd Weekend"),
    heading_color = "black",
    subtitle_color = "gray"
  ) |>
  gt::tab_header(title = gt::html(custom_header)) |>
  gt::tab_source_note(
    source_note = gt::html(
      "<hr>11 of the top-25 teams are still playing and advanced to the Sweet 16.<br>Seven of the top-25 teams advanced to the Round of 32.<br>Four teams were knocked out in the 1st Round or First Four.<br>Three teams missed the tournament entirely.<br><hr><b>Table by Chris at Bless your Chart | data NCAA.com | March 26, 2025</b>"
    )
  ) |>

  gtExtras::gt_add_divider(
    columns = c(`Round of 64`),
    sides = "right",
    color = "black"
  ) |>
  gtUtils::gt_border_bars_bottom(c("#636363", "#969696", "#cccccc")) |>
  gt::tab_options(table.width = gt::px(575)) |>
  gt::tab_style(
    locations = gt::cells_row_groups(),
    style = list(
      gt::cell_text(
        font = gt::google_font("Signika Negative"),
        weight = 850,
        size = gt::px(11.5),
        color = "black",
        align = "left"
      ),
      gt::cell_fill(color = "#C5C5FF")
    )
  ) |>
  gt::tab_style(
    locations = gt::cells_column_spanners(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      weight = 850,
      size = gt::px(14)
    )
  ) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(10),
      weight = 250
    )
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5)
    )),
    locations = gt::cells_body(
      rows = gt::everything(),
      columns = gt::everything()
    )
  ) |>
  gtUtils::gt_border_grid(color = "black",
                          weight = 2,
                          include_labels = FALSE) |> 
  gt::tab_style(
    style = gt::cell_fill(color = "#fdeba9", alpha = 0.6),  # SEC color
    locations = gt::cells_body(columns = Team, rows = c(2, 4, 7, 10:12,
                                                        14, 16, 21,
                                                        23, 24))
  ) |> 
   gt::tab_style(
    style = gt::cell_fill(color = "lightpink", alpha = 0.6),  # SEC color
    locations = gt::cells_body(columns = Team, rows = c(17, 20, 25))
  )


