ncaat_shots_tbl <- ncaalog_wide |>
  dplyr::mutate(across(ends_with("made_attempt"), ~ tidyr::replace_na(., "-")),
                across(ends_with("pct_3"), ~ tidyr::replace_na(., 0))) |>
  dplyr::arrange(-year) |>
  gt::gt() |>
  gtExtras::gt_theme_dot_matrix() |>
  gtExtras::gt_merge_stack(
    col1 = First4_pct_3,
    col2 = First4_made_attempt,
    palette = c("black", "#333333")
  ) |>
  gtExtras::gt_merge_stack(
    col1 = R64_pct_3,
    col2 = R64_made_attempt,
    palette = c("black", "#333333")
  ) |>
  gtExtras::gt_merge_stack(
    col1 = R32_pct_3,
    col2 = R32_made_attempt,
    palette = c("black", "#333333")
  ) |>
  gtExtras::gt_merge_stack(
    col1 = S16_pct_3,
    col2 = S16_made_attempt,
    palette = c("black", "#333333")
  ) |>
  gtExtras::gt_merge_stack(
    col1 = E8_pct_3,
    col2 = E8_made_attempt,
    palette = c("black", "#333333")
  ) |>
  gtExtras::gt_merge_stack(
    col1 = Final4_pct_3,
    col2 = Final4_made_attempt,
    palette = c("black", "#333333")
  ) |>
  gtExtras::gt_merge_stack(
    col1 = F2_pct_3,
    col2 = F2_made_attempt,
    palette = c("black", "#333333")
  ) |>
  gt::fmt_percent(columns = ends_with("pct_3"), decimals = 1) |>
   gt::fmt(
    columns = ends_with("pct_3"),
    fns = function(x) {
      dplyr::case_when(
        x == 0 ~ "-",   # Replace 0.0% with "-"
        TRUE ~ scales::percent(x, accuracy = 0.1)  # Format as percentage
      )
    }
  ) |> 
        gt::data_color(
          columns = ends_with("pct_3"),
          palette = c("#d7191c", "#fdae61", "#ffffbf", "#a6d96a", "#1a9641"),
          # Middle color is neutral
          alpha = 0.4
        ) |>
        gt::tab_style(
          style = gt::cell_fill(color = "#eeeeee"),
          # Light grey background
          locations = gt::cells_body(
            columns = c(S16_pct_3, E8_pct_3, Final4_pct_3, F2_pct_3),
            rows = year == 2025  # Only target 2025 rows
          )
        ) |>
        gt::tab_options (
          source_notes.font.size = gt::px(10),
          row.striping.background_color = 'white',
          column_labels.text_transform = 'none'
        ) |>
        gt::tab_style(
          locations = gt::cells_column_labels(),
          style = gt::cell_text(weight = 850, )
        ) |>
        gtUtils::gt_column_subheaders(
          First4_pct_3 = list(heading = "First 4", subtitle = "3PTM-3PTA"),
          R64_pct_3 = list(heading = "1st Round", subtitle = "Round of 64"),
          R32_pct_3 = list(heading = "2nd Round", subtitle = "Round of 32"),
          S16_pct_3 = list(heading = "Sweet 16", subtitle = "3PTM-3PTA"),
          E8_pct_3 = list(heading = "Elite 8", subtitle = "3PTM-3PTA"),
          Final4_pct_3 = list(heading = "Final 4", subtitle = "3PTM-3PTA"),
          F2_pct_3 = list(heading = "Title Game", subtitle = "3PTM-3PTA"),
          heading_color = "black",
          subtitle_color = "gray"
        ) |>
        gt::cols_label(year = "Year") |>
        gt::tab_header(
          title = gt::md("**NCAA Tournament: 3PT Shooting by Round Since 2011**"),
          subtitle = "Shows the three-point shooting percentages by round of the NCAA Tournament since 2011."
        ) |>
        gt::tab_source_note(
          source_note = gt::html(
            "NCAA moved back the 3PT line to 22 feet, 1¾ inches at start of 2019-20 season.<br>Data through March 23, 2025 games<hr><br><b>Table by Chris at Bless your chart <br> data via barttorvik.com and @cobrastats</b>"
          )
        ) |>
        gtUtils::gt_border_grid(color = "black",
                                weight = 2,
                                include_labels = FALSE)

gtUtils::gt_save_crop(
        ncaat_shots_tbl,
        file = "ncaat_shots_tbl.png",
        whitespace = 40,
        bg = "white"
    )

